import {
  Select as SelectPrimitive,
  type CollectionItem,
  type SelectRootComponent as ArkSelectRootComponent,
  type SelectRootProps as ArkSelectRootProps,
  type SelectRootProviderComponent as ArkSelectRootProviderComponent,
  type SelectRootProviderProps as ArkSelectRootProviderProps,
  useSelect,
  useSelectContext,
  useSelectItemContext,
} from '@ark-ui/react/select';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, ForwardedRef, ReactElement, ReactNode } from 'react';
import { Children, cloneElement, forwardRef } from 'react';
import { CheckIcon, ChevronUpDownIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import {
  OverlayPortal,
  OverlayPortalProvider,
  type OverlayPortalProps,
} from '@/lib/moduix/overlayPortal';
import { CloseButton } from '../close-button';
import styles from './Select.module.css';

type SelectNativeFormControl = 'select' | 'input';
type SelectRootOwnProps = OverlayPortalProps & {
  nativeFormControl?: SelectNativeFormControl;
};
type SelectRootProps<T extends CollectionItem> = ArkSelectRootProps<T> & SelectRootOwnProps;
type SelectRootProviderProps<T extends CollectionItem> = ArkSelectRootProviderProps<T> &
  SelectRootOwnProps;
type SelectRootComponent = ArkSelectRootComponent<SelectRootOwnProps>;
type SelectRootProviderComponent = ArkSelectRootProviderComponent<SelectRootOwnProps>;
type SelectFieldProps = Omit<
  ComponentProps<typeof SelectPrimitive.Control>,
  'asChild' | 'children'
> & {
  clearLabel?: string;
  indicator?: ReactNode;
  placeholder?: ComponentProps<typeof SelectPrimitive.ValueText>['placeholder'];
};

const SelectRoot = forwardRef(function SelectRoot<T extends CollectionItem>(
  {
    asChild,
    children,
    className,
    nativeFormControl = 'select',
    portalled,
    portalRef,
    ...props
  }: SelectRootProps<T>,
  ref: ForwardedRef<HTMLDivElement>,
) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <SelectPrimitive.Root
        ref={ref}
        data-slot="select-root"
        className={clsx(styles.root, normalizeClassName(className))}
        asChild={asChild}
        {...props}
      >
        {withNativeFormControl(children, asChild, nativeFormControl)}
      </SelectPrimitive.Root>
    </OverlayPortalProvider>
  );
}) as SelectRootComponent;

const SelectRootProvider = forwardRef(function SelectRootProvider<T extends CollectionItem>(
  {
    asChild,
    children,
    className,
    nativeFormControl = 'select',
    portalled,
    portalRef,
    ...props
  }: SelectRootProviderProps<T>,
  ref: ForwardedRef<HTMLDivElement>,
) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <SelectPrimitive.RootProvider
        ref={ref}
        data-slot="select-root-provider"
        className={clsx(styles.root, normalizeClassName(className))}
        asChild={asChild}
        {...props}
      >
        {withNativeFormControl(children, asChild, nativeFormControl)}
      </SelectPrimitive.RootProvider>
    </OverlayPortalProvider>
  );
}) as SelectRootProviderComponent;

const SelectLabel = forwardRef<
  ComponentRef<typeof SelectPrimitive.Label>,
  ComponentProps<typeof SelectPrimitive.Label>
>(function SelectLabel({ className, ...props }, ref) {
  return (
    <SelectPrimitive.Label
      ref={ref}
      data-slot="select-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectControl = forwardRef<
  ComponentRef<typeof SelectPrimitive.Control>,
  ComponentProps<typeof SelectPrimitive.Control>
>(function SelectControl({ className, ...props }, ref) {
  return (
    <SelectPrimitive.Control
      ref={ref}
      data-slot="select-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectTrigger = forwardRef<
  ComponentRef<typeof SelectPrimitive.Trigger>,
  ComponentProps<typeof SelectPrimitive.Trigger>
>(function SelectTrigger({ asChild, className, ...props }, ref) {
  return (
    <SelectPrimitive.Trigger
      ref={ref}
      data-slot="select-trigger"
      asChild={asChild}
      className={clsx(!asChild && styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectValueText = forwardRef<
  ComponentRef<typeof SelectPrimitive.ValueText>,
  ComponentProps<typeof SelectPrimitive.ValueText>
>(function SelectValueText({ className, ...props }, ref) {
  return (
    <SelectPrimitive.ValueText
      ref={ref}
      data-slot="select-value-text"
      className={clsx(styles.valueText, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectClearTrigger = forwardRef<
  ComponentRef<typeof SelectPrimitive.ClearTrigger>,
  ComponentProps<typeof SelectPrimitive.ClearTrigger>
>(function SelectClearTrigger(
  {
    asChild,
    className,
    children,
    'aria-label': ariaLabel,
    'aria-labelledby': ariaLabelledBy,
    ...props
  },
  ref,
) {
  const triggerClassName = clsx(styles.clearTrigger, normalizeClassName(className));

  if (asChild) {
    return (
      <SelectPrimitive.ClearTrigger
        ref={ref}
        asChild
        data-slot="select-clear-trigger"
        className={triggerClassName}
        aria-label={ariaLabel}
        aria-labelledby={ariaLabelledBy}
        {...props}
      >
        {children}
      </SelectPrimitive.ClearTrigger>
    );
  }

  return (
    <SelectPrimitive.ClearTrigger
      ref={ref}
      asChild
      data-slot="select-clear-trigger"
      className={triggerClassName}
      {...props}
    >
      <CloseButton.Root
        aria-label={ariaLabel ?? (ariaLabelledBy == null ? 'Clear selection' : undefined)}
        aria-labelledby={ariaLabelledBy}
      >
        {children}
      </CloseButton.Root>
    </SelectPrimitive.ClearTrigger>
  );
});

const SelectIndicator = forwardRef<
  ComponentRef<typeof SelectPrimitive.Indicator>,
  ComponentProps<typeof SelectPrimitive.Indicator>
>(function SelectIndicator({ className, children, ...props }, ref) {
  return (
    <SelectPrimitive.Indicator
      ref={ref}
      data-slot="select-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      {...props}
    >
      {children ?? <ChevronUpDownIcon />}
    </SelectPrimitive.Indicator>
  );
});

const SelectField = forwardRef<ComponentRef<typeof SelectPrimitive.Control>, SelectFieldProps>(
  function SelectField({ clearLabel, indicator, placeholder, ...props }, ref) {
    return (
      <SelectControl ref={ref} {...props}>
        <SelectTrigger>
          <SelectValueText placeholder={placeholder} />
          <SelectIndicator>{indicator}</SelectIndicator>
        </SelectTrigger>
        {clearLabel && <SelectClearTrigger aria-label={clearLabel} />}
      </SelectControl>
    );
  },
);

const SelectPositioner = forwardRef<
  ComponentRef<typeof SelectPrimitive.Positioner>,
  ComponentProps<typeof SelectPrimitive.Positioner>
>(function SelectPositioner({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <SelectPrimitive.Positioner
        ref={ref}
        data-slot="select-positioner"
        className={clsx(styles.positioner, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const SelectContent = forwardRef<
  ComponentRef<typeof SelectPrimitive.Content>,
  ComponentProps<typeof SelectPrimitive.Content>
>(function SelectContent({ className, ...props }, ref) {
  return (
    <SelectPrimitive.Content
      ref={ref}
      data-slot="select-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectList = forwardRef<
  ComponentRef<typeof SelectPrimitive.List>,
  ComponentProps<typeof SelectPrimitive.List>
>(function SelectList({ className, ...props }, ref) {
  return (
    <SelectPrimitive.List
      ref={ref}
      data-slot="select-list"
      className={clsx(styles.list, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectItemGroup = forwardRef<
  ComponentRef<typeof SelectPrimitive.ItemGroup>,
  ComponentProps<typeof SelectPrimitive.ItemGroup>
>(function SelectItemGroup({ className, ...props }, ref) {
  return (
    <SelectPrimitive.ItemGroup
      ref={ref}
      data-slot="select-item-group"
      className={clsx(styles.itemGroup, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectItemGroupLabel = forwardRef<
  ComponentRef<typeof SelectPrimitive.ItemGroupLabel>,
  ComponentProps<typeof SelectPrimitive.ItemGroupLabel>
>(function SelectItemGroupLabel({ className, ...props }, ref) {
  return (
    <SelectPrimitive.ItemGroupLabel
      ref={ref}
      data-slot="select-item-group-label"
      className={clsx(styles.itemGroupLabel, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectItem = forwardRef<
  ComponentRef<typeof SelectPrimitive.Item>,
  ComponentProps<typeof SelectPrimitive.Item>
>(function SelectItem({ className, ...props }, ref) {
  return (
    <SelectPrimitive.Item
      ref={ref}
      data-slot="select-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectItemText = forwardRef<
  ComponentRef<typeof SelectPrimitive.ItemText>,
  ComponentProps<typeof SelectPrimitive.ItemText>
>(function SelectItemText({ className, ...props }, ref) {
  return (
    <SelectPrimitive.ItemText
      ref={ref}
      data-slot="select-item-text"
      className={clsx(styles.itemText, normalizeClassName(className))}
      {...props}
    />
  );
});

const SelectItemIndicator = forwardRef<
  ComponentRef<typeof SelectPrimitive.ItemIndicator>,
  ComponentProps<typeof SelectPrimitive.ItemIndicator>
>(function SelectItemIndicator({ className, children, ...props }, ref) {
  return (
    <SelectPrimitive.ItemIndicator
      ref={ref}
      data-slot="select-item-indicator"
      className={clsx(styles.itemIndicator, normalizeClassName(className))}
      {...props}
    >
      {children ?? <CheckIcon />}
    </SelectPrimitive.ItemIndicator>
  );
});

function withNativeFormControl(
  children: ReactNode,
  asChild: boolean | undefined,
  nativeFormControl: SelectNativeFormControl,
) {
  const formControl = <SelectFormControl nativeFormControl={nativeFormControl} />;

  if (!asChild) {
    return (
      <>
        {children}
        {formControl}
      </>
    );
  }

  const child = Children.only(children) as ReactElement<{ children?: ReactNode }>;

  return cloneElement(child, {}, child.props.children, formControl);
}

function SelectFormControl({ nativeFormControl }: { nativeFormControl: SelectNativeFormControl }) {
  const select = useSelectContext();

  if (nativeFormControl === 'select') {
    return <SelectPrimitive.HiddenSelect data-slot="select-hidden-select" />;
  }

  const hiddenSelectProps = select.getHiddenSelectProps();

  return (
    <>
      {select.value.map((value) => (
        <input
          key={value}
          type="hidden"
          data-slot="select-hidden-input"
          name={hiddenSelectProps.name}
          form={hiddenSelectProps.form}
          autoComplete={hiddenSelectProps.autoComplete}
          disabled={hiddenSelectProps.disabled}
          value={value}
        />
      ))}
    </>
  );
}

function SelectItemTextContent({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="select-item-text-content"
      className={clsx(styles.itemTextContent, normalizeClassName(className))}
      {...props}
    />
  );
}

function SelectItemTextIcon({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="select-item-text-icon"
      className={clsx(styles.itemTextIcon, normalizeClassName(className))}
      {...props}
    />
  );
}

function SelectItemTextLabel({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="select-item-text-label"
      className={clsx(styles.itemTextLabel, normalizeClassName(className))}
      {...props}
    />
  );
}

const Select = Object.assign(SelectRoot, {
  Root: SelectRoot,
  RootProvider: SelectRootProvider,
  Context: SelectPrimitive.Context,
  ItemContext: SelectPrimitive.ItemContext,
  useSelect,
  useSelectContext,
  useSelectItemContext,
  Label: SelectLabel,
  Control: SelectControl,
  Field: SelectField,
  Trigger: SelectTrigger,
  ValueText: SelectValueText,
  ClearTrigger: SelectClearTrigger,
  Indicator: SelectIndicator,
  Positioner: SelectPositioner,
  Content: SelectContent,
  List: SelectList,
  ItemGroup: SelectItemGroup,
  ItemGroupLabel: SelectItemGroupLabel,
  Item: SelectItem,
  ItemText: SelectItemText,
  ItemIndicator: SelectItemIndicator,
  ItemTextContent: SelectItemTextContent,
  ItemTextIcon: SelectItemTextIcon,
  ItemTextLabel: SelectItemTextLabel,
});

export { Select, useSelect, useSelectContext, useSelectItemContext };

@layer moduix.components {
  @keyframes select-content-open {
    from {
      opacity: var(
        --moduix-select-content-closed-opacity,
        var(--moduix-popup-motion-starting-opacity, 0)
      );
      translate: var(--moduix-popup-motion-starting-translate-x, 0)
        var(--moduix-popup-motion-starting-translate-y, 0);
      transform: scale(
        var(
          --moduix-select-content-closed-scale,
          var(--moduix-popup-motion-starting-scale, var(--moduix-scale-popup))
        )
      );
    }

    to {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }
  }

  @keyframes select-content-closed {
    from {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }

    to {
      opacity: var(
        --moduix-select-content-closed-opacity,
        var(--moduix-popup-motion-ending-opacity, 0)
      );
      translate: var(--moduix-popup-motion-ending-translate-x, 0)
        var(--moduix-popup-motion-ending-translate-y, 0);
      transform: scale(
        var(
          --moduix-select-content-closed-scale,
          var(--moduix-popup-motion-ending-scale, var(--moduix-scale-popup))
        )
      );
    }
  }

  .root {
    box-sizing: border-box;
    display: flex;
    width: var(--moduix-select-width, 14rem);
    max-width: var(--moduix-select-max-width, 100%);
    min-width: 0;
    flex-direction: column;
    gap: var(--moduix-select-root-gap, var(--moduix-spacing-1-5));
    color: var(--moduix-select-color, var(--moduix-color-foreground));
  }

  .label {
    display: inline-flex;
    align-items: center;
    color: var(
      --moduix-select-label-color,
      var(--moduix-select-color, var(--moduix-color-foreground))
    );
    font-size: var(--moduix-select-label-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-select-label-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-select-label-line-height, var(--moduix-line-height-text-sm));
    user-select: none;

    &[data-disabled] {
      opacity: var(--moduix-select-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .control {
    position: relative;
    display: flex;
    width: 100%;
    min-width: 0;
    align-items: center;
    color: var(--moduix-select-color, var(--moduix-color-foreground));

    &[data-disabled] {
      opacity: var(--moduix-select-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .trigger {
    position: relative;
    box-sizing: border-box;
    display: inline-flex;
    width: 100%;
    min-width: 0;
    height: var(--moduix-select-control-height, var(--moduix-size-md));
    align-items: center;
    justify-content: flex-start;
    margin: 0;
    border: var(--moduix-select-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-select-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-select-radius, var(--moduix-radius-md));
    padding-inline: var(--moduix-select-trigger-padding-x-start, var(--moduix-spacing-3-5))
      calc(
        var(--moduix-select-action-offset-right, var(--moduix-spacing-2)) +
          var(--moduix-select-action-size, var(--moduix-size-xs)) +
          var(--moduix-select-trigger-padding-x-start, var(--moduix-spacing-3-5))
      );
    background-color: var(--moduix-select-bg, var(--moduix-color-background));
    color: inherit;
    font: inherit;
    text-align: start;
    outline: var(
        --moduix-select-focus-ring-width,
        var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
      )
      solid transparent;
    outline-offset: calc(
      var(
          --moduix-select-focus-ring-width,
          var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        ) *
        -1
    );
    cursor: pointer;
    user-select: none;
    transition:
      background-color var(--moduix-select-transition, var(--moduix-transition-default)),
      border-color var(--moduix-select-transition, var(--moduix-transition-default)),
      outline-color var(--moduix-select-transition, var(--moduix-transition-default));

    &[data-placeholder-shown] {
      color: var(--moduix-select-placeholder-color, var(--moduix-color-muted-foreground));
    }

    &[data-state='open'] {
      border-color: var(--moduix-select-focus-ring-color, var(--moduix-color-ring));
      outline-color: var(--moduix-select-focus-ring-color, var(--moduix-color-ring));
    }

    &[data-disabled],
    &[disabled] {
      cursor: default;
    }

    &:focus-visible {
      border-color: var(--moduix-select-focus-ring-color, var(--moduix-color-ring));
      outline-color: var(--moduix-select-focus-ring-color, var(--moduix-color-ring));
    }

    .control[data-invalid] & {
      border-color: var(--moduix-select-invalid-color, var(--moduix-color-destructive));
      outline-color: var(--moduix-select-invalid-color, var(--moduix-color-destructive));
    }
  }

  .control:has(.clearTrigger:not([hidden])) .trigger {
    padding-inline-end: var(--moduix-select-trigger-padding-x-end, 4.25rem);
  }

  .valueText {
    min-width: 0;
    flex: 1;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .indicator {
    box-sizing: border-box;
    display: inline-flex;
    width: var(--moduix-select-action-size, var(--moduix-size-xs));
    height: var(--moduix-select-action-size, var(--moduix-size-xs));
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    margin: 0;
    border: 0;
    border-radius: var(--moduix-select-action-radius, var(--moduix-radius-sm));
    padding: 0;
    background: var(--moduix-select-action-bg, transparent);
    color: var(--moduix-select-icon-color, var(--moduix-color-muted-foreground));
    line-height: 0;
    transition:
      background-color var(--moduix-select-transition, var(--moduix-transition-default)),
      color var(--moduix-select-transition, var(--moduix-transition-default)),
      opacity var(--moduix-select-transition, var(--moduix-transition-default));

    & > svg {
      display: block;
      width: var(--moduix-select-icon-size, var(--moduix-spacing-4));
      height: var(--moduix-select-icon-size, var(--moduix-spacing-4));
    }

    &[data-disabled],
    &[disabled] {
      cursor: default;
    }

    &[hidden] {
      display: none;
    }
  }

  .indicator {
    pointer-events: none;
  }

  .trigger > .indicator {
    pointer-events: auto;
  }

  .trigger > .indicator {
    position: absolute;
    top: 50%;
    inset-inline-end: var(--moduix-select-action-offset-right, var(--moduix-spacing-2));
    transform: translateY(-50%);
  }

  .trigger > .indicator:not(:is([data-disabled], [disabled])):hover {
    @media (hover: hover) {
      background-color: var(--moduix-select-action-bg-hover, var(--moduix-color-muted));
      color: var(--moduix-select-action-color-hover, var(--moduix-color-foreground));
    }
  }

  .clearTrigger {
    --moduix-close-button-size: var(--moduix-select-action-size, var(--moduix-size-xs));
    --moduix-close-button-icon-size: var(--moduix-select-icon-size, var(--moduix-spacing-4));
    --moduix-close-button-radius: var(--moduix-select-action-radius, var(--moduix-radius-sm));
    --moduix-close-button-bg: var(--moduix-select-action-bg, transparent);
    --moduix-close-button-bg-hover: var(--moduix-select-action-bg-hover, var(--moduix-color-muted));
    --moduix-close-button-color: var(
      --moduix-select-icon-color,
      var(--moduix-color-muted-foreground)
    );
    --moduix-close-button-color-hover: var(
      --moduix-select-action-color-hover,
      var(--moduix-color-foreground)
    );
    --moduix-close-button-transition: var(
      --moduix-select-transition,
      var(--moduix-transition-default)
    );

    pointer-events: auto;

    &[hidden] {
      display: none;
    }
  }

  .control > .clearTrigger {
    position: absolute;
    top: 50%;
    inset-inline-end: calc(
      var(--moduix-select-action-offset-right, var(--moduix-spacing-2)) +
        var(--moduix-select-action-size, var(--moduix-size-xs)) +
        var(--moduix-select-action-gap, var(--moduix-spacing-0-5))
    );
    transform: translateY(-50%);
  }

  .positioner {
    z-index: var(--z-index);
    outline: 0;
  }

  .content {
    box-sizing: border-box;
    z-index: calc(var(--moduix-z-popup) + var(--layer-index, 0));
    display: flex;
    min-width: var(--reference-width);
    max-width: var(--available-width);
    max-height: min(var(--moduix-select-content-max-height, 24rem), var(--available-height));
    flex-direction: column;
    overflow: auto;
    border: var(--moduix-select-content-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-select-content-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-select-radius, var(--moduix-radius-md));
    padding-block: var(
      --moduix-select-content-padding-y,
      var(--moduix-popup-list-padding-y, var(--moduix-spacing-1))
    );
    background-color: var(--moduix-select-content-bg, var(--moduix-color-popover));
    box-shadow: var(--moduix-select-content-shadow, var(--moduix-shadow-lg));
    color: var(--moduix-select-content-color, var(--moduix-color-popover-foreground));
    transform-origin: var(--transform-origin);
    outline: 0;
    overscroll-behavior: contain;
    scroll-padding-block: var(--moduix-select-content-padding-y, var(--moduix-spacing-1));

    &[data-state='open'] {
      animation: select-content-open
        var(
          --moduix-select-transition,
          var(--moduix-popup-motion-duration, var(--moduix-duration-normal))
            var(--moduix-popup-motion-easing, var(--moduix-ease-in-out))
        );
    }

    &[data-state='closed'] {
      animation: select-content-closed
        var(
          --moduix-select-transition,
          var(--moduix-popup-motion-duration, var(--moduix-duration-normal))
            var(--moduix-popup-motion-easing, var(--moduix-ease-in-out))
        );
      pointer-events: none;
    }
  }

  .list {
    display: flex;
    min-height: 0;
    flex-direction: column;
    overflow-y: auto;
    outline: 0;
    overscroll-behavior: contain;
    scroll-padding-block: var(--moduix-select-content-padding-y, var(--moduix-spacing-1));
  }

  .itemGroup {
    display: flex;
    flex-direction: column;

    & + & {
      margin-top: var(--moduix-select-item-group-gap, var(--moduix-spacing-2));
    }
  }

  .itemGroupLabel {
    padding-block: var(
      --moduix-select-item-group-label-padding-y,
      var(--moduix-popup-group-label-padding-y, var(--moduix-spacing-1))
    );
    padding-inline: var(--moduix-select-item-group-label-padding-x, var(--moduix-spacing-2-5));
    color: var(
      --moduix-select-item-group-label-color,
      var(--moduix-popup-group-label-color, var(--moduix-color-muted-foreground))
    );
    font-size: var(
      --moduix-select-item-group-label-font-size,
      var(--moduix-popup-group-label-font-size, var(--moduix-text-xs))
    );
    font-weight: var(
      --moduix-select-item-group-label-font-weight,
      var(--moduix-popup-group-label-font-weight, var(--moduix-weight-regular))
    );
    line-height: var(
      --moduix-select-item-group-label-line-height,
      var(--moduix-popup-group-label-line-height, var(--moduix-line-height-text-xs))
    );
  }

  .item {
    position: relative;
    box-sizing: border-box;
    display: flex;
    width: calc(100% - var(--moduix-select-item-inset-x, var(--moduix-spacing-2)));
    min-height: var(
      --moduix-select-item-min-height,
      var(--moduix-popup-item-min-height, var(--moduix-size-sm))
    );
    align-items: center;
    justify-content: space-between;
    gap: var(--moduix-select-item-gap, var(--moduix-spacing-2));
    margin-inline: calc(var(--moduix-select-item-inset-x, var(--moduix-spacing-2)) / 2);
    border: var(--moduix-select-item-border-width, 0) solid
      var(--moduix-select-item-border-color, transparent);
    border-radius: var(--moduix-select-item-radius, var(--moduix-radius-sm));
    padding-block: var(
      --moduix-select-item-padding-y,
      var(--moduix-popup-item-padding-y, var(--moduix-spacing-1))
    );
    padding-inline: var(
      --moduix-select-item-padding-x,
      var(--moduix-popup-item-padding-x-start, var(--moduix-spacing-3))
    );
    background-color: var(--moduix-select-item-bg, transparent);
    color: var(
      --moduix-select-item-color,
      var(--moduix-select-content-color, var(--moduix-color-foreground))
    );
    font: inherit;
    font-size: var(
      --moduix-select-item-font-size,
      var(--moduix-popup-item-font-size, var(--moduix-text-sm))
    );
    line-height: var(
      --moduix-select-item-line-height,
      var(--moduix-popup-item-line-height, var(--moduix-line-height-text-sm))
    );
    outline: 0;
    user-select: none;
    cursor: default;

    &[data-highlighted] {
      background-color: var(--moduix-select-highlight-bg, var(--moduix-color-accent));
      color: var(--moduix-select-highlight-color, var(--moduix-color-accent-foreground));
    }

    &[data-state='checked'] {
      color: var(
        --moduix-select-item-checked-color,
        var(--moduix-select-item-color, var(--moduix-color-foreground))
      );
    }

    &[data-disabled] {
      pointer-events: none;
      color: var(--moduix-select-item-disabled-color, var(--moduix-color-muted-foreground));
      opacity: var(--moduix-select-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .itemText {
    min-width: 0;
    flex: 1;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .itemIndicator {
    display: inline-flex;
    width: var(--moduix-select-item-indicator-size, var(--moduix-spacing-3-5));
    height: var(--moduix-select-item-indicator-size, var(--moduix-spacing-3-5));
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    color: var(--moduix-select-item-indicator-color, currentColor);

    & > svg {
      width: var(--moduix-select-item-indicator-icon-size, var(--moduix-spacing-3));
      height: var(--moduix-select-item-indicator-icon-size, var(--moduix-spacing-3));
    }
  }

  .itemTextContent {
    display: inline-flex;
    max-width: 100%;
    min-width: 0;
    align-items: center;
    gap: var(--moduix-select-item-text-content-gap, var(--moduix-spacing-2));
    vertical-align: top;
  }

  .itemTextIcon {
    display: inline-flex;
    width: var(--moduix-select-item-text-icon-size, var(--moduix-spacing-4));
    height: var(--moduix-select-item-text-icon-size, var(--moduix-spacing-4));
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    color: var(--moduix-select-item-text-icon-color, currentColor);
  }

  .itemTextLabel {
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
}
